patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..694576767c63 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,43 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  // Handle the case where both fcmps compare the same value against constants
+  // with the same predicate: (fcmp P X, C0) op (fcmp P X, C1)
+  if (LHS0 == RHS0 && PredL == PredR) {
+    const APFloat *C0, *C1;
+    if (match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
+      // For predicates where "less constant" means stricter:
+      // - olt, ole, ult, ule: X < C - smaller C is stricter
+      // - ogt, oge, ugt, uge: X > C - larger C is stricter
+      bool IsLessThanPred = (PredL == FCmpInst::FCMP_OLT ||
+                              PredL == FCmpInst::FCMP_OLE ||
+                              PredL == FCmpInst::FCMP_ULT ||
+                              PredL == FCmpInst::FCMP_ULE);
+      bool IsGreaterThanPred = (PredL == FCmpInst::FCMP_OGT ||
+                                 PredL == FCmpInst::FCMP_OGE ||
+                                 PredL == FCmpInst::FCMP_UGT ||
+                                 PredL == FCmpInst::FCMP_UGE);
+      
+      if (IsLessThanPred) {
+        // For X < C: smaller C is stricter
+        // OR: return looser (larger constant)
+        // AND: return stricter (smaller constant)
+        if (C0->compare(*C1) == APFloat::cmpLessThan)
+          return IsAnd ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+        if (C1->compare(*C0) == APFloat::cmpLessThan)
+          return IsAnd ? static_cast<Value *>(RHS) : static_cast<Value *>(LHS);
+      } else if (IsGreaterThanPred) {
+        // For X > C: larger C is stricter
+        // OR: return looser (smaller constant)
+        // AND: return stricter (larger constant)
+        if (C0->compare(*C1) == APFloat::cmpGreaterThan)
+          return IsAnd ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+        if (C1->compare(*C0) == APFloat::cmpGreaterThan)
+          return IsAnd ? static_cast<Value *>(RHS) : static_cast<Value *>(LHS);
+      }
+    }
+  }
+
   return nullptr;
 }

